Part.Source:
For &SdtPedidosItem in &SdtPedidos
	&domPedCod.Add(&SdtPedidosItem.PedCod)
EndFor

&IsDiferente = false
For Each Order EmpCod, FilCod, PedCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCod
	Where PedCod in &domPedCod

	if &PedCliCodRaz.IsEmpty()
		&PedCliCodRaz = PedCliCodRaz
		&PedCod = PedCod
	Endif

	if &PedCliCodRaz <> PedCliCodRaz
		&IsDiferente = true
	Endif

	//		if PedSts = Status_Pedido.ABERTO
	//			Form.Caption = '#SUPOSTAS FALTAS DOS PEDIDOS'
	//			
	//			aviso.Caption = 'Selecionado pedido com status ABERTO, essa situação ainda poderá ser alterada!'
	//			aviso.ForeColor = RGB(200,150,0)
	//		EndIF

	For each order EmpCod, FilCod, PedCod
		Where PedQtdCan > 0 when (PedSts = Status_Pedido.FECHADO or PedSts = Status_Pedido.SEPARANDO)
		Where PedQtd > 0 when (PedSts <> Status_Pedido.FECHADO and PedSts <> Status_Pedido.SEPARANDO)

		&IsAchou = false
		For &sdtPedidoProdutoItem in &SdtPedidosProdutos
			if &sdtPedidoProdutoItem.ProGraRef = ProGraRef
				&IsAchou = true

				//&EstQtd = &sdtPedidoProdutoItem.EstQtd

				&sdtPedidoProdutoItem.PedQtd += PedQtd

				//Qtd Falta
				If (PedSts = Status_Pedido.FECHADO or PedSts = Status_Pedido.SEPARANDO)
					&sdtPedidoProdutoItem.PedQtdFec += PedQtd
					&sdtPedidoProdutoItem.PedQtdFecCan += PedQtdCan
				EndIf
				//if &EstQtd < 0
				//		&PedqtdCan = PedQtd
				//	Else
				//		&PedqtdCan = PedQtd - &EstQtd
				//	EndIf
				//EndIf
				//if &PedqtdCan < 0
				//	&PedqtdCan = 0
				//Endif
				&sdtPedidoProdutoItem.PedQtdCan = (&sdtPedidoProdutoItem.PedQtd-&sdtPedidoProdutoItem.PedQtdFec) - &sdtPedidoProdutoItem.EstQtd
				if &sdtPedidoProdutoItem.PedQtdCan < 0
					&sdtPedidoProdutoItem.PedQtdCan = 0
				Endif			
				&sdtPedidoProdutoItem.PedQtdCan += &sdtPedidoProdutoItem.PedQtdFecCan

				//Valor Total Falta
				//&PedVlrItm = (PedVlrUnt * &sdtPedidoProdutoItem.PedQtdCan)
				&sdtPedidoProdutoItem.PedVlrItmVen += PedVlrItm
				if &sdtPedidoProdutoItem.PedVlrItmVen > 0 and &sdtPedidoProdutoItem.PedQtd > 0 and &sdtPedidoProdutoItem.PedQtdCan > 0
					&sdtPedidoProdutoItem.PedVlrItm = (&sdtPedidoProdutoItem.PedVlrItmVen / &sdtPedidoProdutoItem.PedQtd) * &sdtPedidoProdutoItem.PedQtdCan
				Else
					&sdtPedidoProdutoItem.PedVlrItm = 0
				Endif

				&TotalFaltas = &sdtPedidoProdutoItem.PedVlrItm

				Exit
			Endif
		EndFor

		if &IsAchou = false
			&sdtPedidoProdutoItem = new()

			&sdtPedidoProdutoItem.EmpCod		= EmpCod
			&sdtPedidoProdutoItem.ProCod 		= ProCod
			&sdtPedidoProdutoItem.ProGraCod 	= ProGraCod
			&sdtPedidoProdutoItem.ProGraRef 	= ProGraRef
			&sdtPedidoProdutoItem.ProGraRefPadL = ProGraRefPadL
			&sdtPedidoProdutoItem.ProEstProRef 	= ProEstProRef
			&sdtPedidoProdutoItem.ProNom 		= ProNomGra
			&sdtPedidoProdutoItem.PedQtd 		= PedQtd
			&sdtPedidoProdutoItem.EstLoc		= EstLoc
			&sdtPedidoProdutoItem.PedCliCodRaz 	= &PedCliCodRaz
			&sdtPedidoProdutoItem.PedCod 	= &PedCod
			&sdtPedidoProdutoItem.ProEstProCod 	= PedProEstProCod
			&sdtPedidoProdutoItem.ProEstProGraCod = PedProEstProGraCod

			RetornaQuantidadeEstoque.Call(EmpCod, FilCod, PedProEstProCod, PedProEstProGraCod, &EstCom, &EstVen, &EstPrd, &EstQtd, &EstSdo, &EstSug, &EstQtdFis)
			RetornaQuantidadeEstoqueSimilar.Call(EmpCod, FilCod, PedProEstProCod, PedProEstProGraCod, &SimEstQtd)
			&sdtPedidoProdutoItem.EstQtd = &EstQtd
			&sdtPedidoProdutoItem.SimEstQtd = &SimEstQtd

			//			//Qtd Falta
			//			If (PedSts = Status_Pedido.FECHADO or PedSts = Status_Pedido.SEPARANDO)
			//				&PedQtdCan = PedQtdCan
			//			Else		
			//				if &EstQtd < 0
			//					&PedqtdCan = PedQtd
			//				Else
			//					&PedqtdCan = PedQtd - &EstQtd
			//				EndIf
			//			EndIf
			//			
			//			if &PedqtdCan <= 0
			//				&PedqtdCan = 0
			//			Else
			//				&sdtPedidoProdutoItem.PedQtdCan = &PedqtdCan
			//				
			//				//Valor Total Falta
			//				&PedVlrItm = (PedVlrUnt * &PedQtdCan)
			//				&sdtPedidoProdutoItem.PedVlrItm = &PedVlrItm
			//				
			//				&TotalFaltas += &PedVlrItm
			//				&SdtPedidosProdutos.Add(&sdtPedidoProdutoItem)
			//			EndiF


			//Qtd Falta
			If (PedSts = Status_Pedido.FECHADO or PedSts = Status_Pedido.SEPARANDO)
				&sdtPedidoProdutoItem.PedQtdFec = PedQtd
				&sdtPedidoProdutoItem.PedQtdFecCan = PedQtdCan
			EndIf

			&sdtPedidoProdutoItem.PedQtdCan = (&sdtPedidoProdutoItem.PedQtd-&sdtPedidoProdutoItem.PedQtdFec) - &sdtPedidoProdutoItem.EstQtd
			if &sdtPedidoProdutoItem.PedQtdCan < 0
				&sdtPedidoProdutoItem.PedQtdCan = 0
			Endif			
			&sdtPedidoProdutoItem.PedQtdCan += &sdtPedidoProdutoItem.PedQtdFecCan

			//Valor Total Falta
			//&PedVlrItm = (PedVlrUnt * &sdtPedidoProdutoItem.PedQtdCan)
			&sdtPedidoProdutoItem.PedVlrItmVen = PedVlrItm
			if &sdtPedidoProdutoItem.PedVlrItmVen > 0 and &sdtPedidoProdutoItem.PedQtd > 0 and &sdtPedidoProdutoItem.PedQtdCan > 0
				&sdtPedidoProdutoItem.PedVlrItm = (&sdtPedidoProdutoItem.PedVlrItmVen / &sdtPedidoProdutoItem.PedQtd) * &sdtPedidoProdutoItem.PedQtdCan
			Else
				&sdtPedidoProdutoItem.PedVlrItm = 0
			Endif

			&SdtPedidosProdutos.Add(&sdtPedidoProdutoItem)

			&TotalFaltas = &sdtPedidoProdutoItem.PedVlrItm

		Endif
	EndFor	
EndFor

if &SomenteComfaltas = true
	For &sdtPedidoProdutoItem in &SdtPedidosProdutos
		if &sdtPedidoProdutoItem.PedQtdCan = 0
			&index = &SdtPedidosProdutos.IndexOf(&sdtPedidoProdutoItem)
			&SdtPedidosProdutos.Remove(&index)
		Endif
	EndFor
Endif

&SdtPedidosProdutos.Sort('ProGraRefPadL')
